import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Login() {
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form);
      toast.success('Welcome back!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{minHeight:'100vh',display:'flex',alignItems:'center',justifyContent:'center',background:'linear-gradient(135deg,#0f172a,#065f46)',padding:'30px'}}>

      <div style={{width:'100%',maxWidth:'500px'}}>

        {/* LOGO */}
        <div style={{textAlign:'center',marginBottom:'35px'}}>
          <h1 style={{fontSize:'48px',fontWeight:'900',color:'#4ade80',letterSpacing:'1px'}}>⚡ TeamTask</h1>
          <p style={{color:'#d1fae5',fontSize:'16px'}}>Smart Team Management Platform</p>
        </div>

        {/* CARD */}
        <div style={{background:'rgba(255,255,255,0.08)',padding:'40px',borderRadius:'20px',backdropFilter:'blur(15px)',boxShadow:'0 20px 60px rgba(0,0,0,0.4)',border:'1px solid rgba(255,255,255,0.2)'}}>

          <h2 style={{textAlign:'center',marginBottom:'25px',fontSize:'26px',fontWeight:'700',color:'#ffffff'}}>Welcome Back 👋</h2>

          <form onSubmit={handleSubmit}>

            <div style={{marginBottom:'18px'}}>
              <label style={{fontSize:'15px',color:'#bbf7d0'}}>Email</label>
              <input
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })}
                required
                style={{width:'100%',padding:'14px',marginTop:'6px',borderRadius:'10px',border:'1px solid rgba(255,255,255,0.3)',fontSize:'16px',background:'rgba(255,255,255,0.1)',color:'#fff',outline:'none'}}
              />
            </div>

            <div style={{marginBottom:'25px'}}>
              <label style={{fontSize:'15px',color:'#bbf7d0'}}>Password</label>
              <input
                type="password"
                placeholder="••••••••"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                required
                style={{width:'100%',padding:'14px',marginTop:'6px',borderRadius:'10px',border:'1px solid rgba(255,255,255,0.3)',fontSize:'16px',background:'rgba(255,255,255,0.1)',color:'#fff',outline:'none'}}
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              style={{width:'100%',padding:'14px',borderRadius:'10px',border:'none',background:'linear-gradient(135deg,#22c55e,#4ade80)',color:'#022c22',fontWeight:'700',fontSize:'17px',cursor:'pointer',transition:'0.3s'}}
            >
              {loading ? 'Signing in...' : 'Sign In →'}
            </button>

          </form>

          <p style={{textAlign:'center',marginTop:'18px',fontSize:'14px',color:'#d1fae5'}}>
            No account? <Link to="/register" style={{color:'#4ade80',fontWeight:'600'}}>Register here</Link>
          </p>

        </div>

        {/* INFO */}
        <div style={{marginTop:'25px',padding:'14px',background:'rgba(255,255,255,0.1)',borderRadius:'12px',fontSize:'14px',color:'#bbf7d0',textAlign:'center'}}>
          💡 Register as <b>admin</b> to create tasks <br />
          Register as <b>member</b> to submit tasks
        </div>

      </div>
    </div>
  );
}
